INSERT INTO public.curriculum_subtopics (topic_id, name, sort_order) SELECT t.id, 'I-V characteristics: forward bias - exponential rise after threshold; reverse bias - almost zero till breakdown', 1 FROM public.curriculum_topics t JOIN public.curriculum_chapters c ON c.id = t.chapter_id JOIN public.curriculum_units u ON u.id = c.unit_id WHERE u.subject='physics' AND u.class_level=12 AND u.unit_label='Unit IX' AND c.title='Semiconductor Electronics' AND t.title='Diode Applications' LIMIT 1;
INSERT INTO public.curriculum_subtopics (topic_id, name, sort_order) SELECT t.id, 'Half-wave rectifier: diode in series with load; only positive half cycles pass; output frequency = input', 2 FROM public.curriculum_topics t JOIN public.curriculum_chapters c ON c.id = t.chapter_id JOIN public.curriculum_units u ON u.id = c.unit_id WHERE u.subject='physics' AND u.class_level=12 AND u.unit_label='Unit IX' AND c.title='Semiconductor Electronics' AND t.title='Diode Applications' LIMIT 1;
INSERT INTO public.curriculum_subtopics (topic_id, name, sort_order) SELECT t.id, 'Full-wave rectifier (centre-tap): two diodes; both half cycles used; output frequency = 2 x input', 3 FROM public.curriculum_topics t JOIN public.curriculum_chapters c ON c.id = t.chapter_id JOIN public.curriculum_units u ON u.id = c.unit_id WHERE u.subject='physics' AND u.class_level=12 AND u.unit_label='Unit IX' AND c.title='Semiconductor Electronics' AND t.title='Diode Applications' LIMIT 1;
INSERT INTO public.curriculum_subtopics (topic_id, name, sort_order) SELECT t.id, 'Bridge rectifier: four diodes; more efficient full-wave rectification; no centre-tap needed', 4 FROM public.curriculum_topics t JOIN public.curriculum_chapters c ON c.id = t.chapter_id JOIN public.curriculum_units u ON u.id = c.unit_id WHERE u.subject='physics' AND u.class_level=12 AND u.unit_label='Unit IX' AND c.title='Semiconductor Electronics' AND t.title='Diode Applications' LIMIT 1;
